// RAKITRAKATRA WEBGL - FIXED v1.0
(function(){
  var R = window.Rakitrakatra || {};
  if(typeof window.Rakitrakatra === 'undefined') window.Rakitrakatra = R;
  
  R.WebGL = function(kianja, opts){
    this.kianja = kianja;
    this.opts = opts || {};
    this.canvas = kianja && kianja.lalao ? kianja.lalao.canvas : null;
    this.gl = null;
    try {
      if(this.canvas){
        this.gl = this.canvas.getContext('webgl') || this.canvas.getContext('experimental-webgl');
      }
    } catch(e){
      console.warn('WebGL not supported');
    }
    if(kianja && kianja.zavatra) kianja.zavatra.push(this);
    console.log('✅ WebGL loaded');
  };
  
  R.WebGL.prototype.havaozy = function(dt){};
  R.WebGL.prototype.soraty = function(ctx){
    if(this.opts.debug && ctx){
      ctx.save();
      ctx.fillStyle = 'rgba(0,255,255,0.1)';
      ctx.fillRect(0,0,100,20);
      ctx.fillStyle = '#0ff';
      ctx.font = '10px monospace';
      ctx.fillText('WEBGL:ON', 5, 13);
      ctx.restore();
    }
  };
  
  // Compatibility - particles checks R.WebGL
  R.WebGL.isSupported = function(){
    try {
      var c = document.createElement('canvas');
      return !!(c.getContext('webgl') || c.getContext('experimental-webgl'));
    } catch(e){ return false; }
  };
  
  console.log('✅ rakitrakatra.webgl.min.js FIXED');
})();
